{
  "schema_version": 1,
  "request_id": "rf-suggest-edit-three-step-priority-chain-001",
  "project": "radishflow",
  "task": "suggest_flowsheet_edits",
  "status": "partial",
  "requires_confirmation": true,
  "answers": [
    {
      "summary": "当前围绕已选中的加热器回路局部问题生成候选提案，重点处理 Heater Feed 缺失规格、Trim Heater 缺失出口温度目标，以及 Heater Outlet 未连接下游导致的拓扑无效问题。",
      "issues": [
        {
          "title": "进料流缺少必要入口规格",
          "details": "Heater Feed 当前仅有压力，缺少温度和流量规格，直接触发流股规格缺失诊断。",
          "citations": [
            "diag-2",
            "flowdoc-stream-1"
          ]
        },
        {
          "title": "加热器控制参数不完整",
          "details": "Trim Heater 已配置为 outlet_temperature 控制，但缺少出口温度目标参数。",
          "citations": [
            "diag-3",
            "flowdoc-unit-1"
          ]
        },
        {
          "title": "出口流未连接下游",
          "details": "Heater Outlet 没有下游消费端或导出端，当前快照也显示拓扑无效；在缺少可用下游对象证据时，只能提出保护性连接占位建议。",
          "citations": [
            "diag-1",
            "flowdoc-stream-2",
            "snapshot-1"
          ]
        }
      ],
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "为 Heater Feed 补充缺失入口规格占位",
          "target": {
            "type": "stream",
            "id": "feed-7"
          },
          "rationale": "该流股被直接诊断为缺少温度和流量规格。使用占位而非臆测数值，可将修改限制在当前选中对象上并保持可审查。",
          "patch": {
            "spec_placeholders": {
              "temperature_c": {
                "reason": "required_by_STREAM_SPEC_MISSING"
              },
              "flow_rate": {
                "reason": "required_by_STREAM_SPEC_MISSING"
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-2",
            "flowdoc-stream-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为 Trim Heater 补充出口温度目标占位",
          "target": {
            "type": "unit",
            "id": "heater-3"
          },
          "rationale": "该设备控制模式已明确为 outlet_temperature，但缺少对应目标参数。补充参数占位可直接对应诊断且不改变现有拓扑。",
          "patch": {
            "parameter_placeholders": {
              "outlet_temperature_target_c": {
                "reason": "required_by_UNIT_PARAMETER_INCOMPLETE"
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-3",
            "flowdoc-unit-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为 Heater Outlet 添加下游连接占位",
          "target": {
            "type": "stream",
            "id": "product-7"
          },
          "rationale": "当前仅有证据表明该出口流未连接，且快照显示拓扑无效；由于请求中没有可用下游单元或出口端对象，建议只添加非执行式连接占位，留待人工确认具体去向。",
          "patch": {
            "connection_placeholder": {
              "endpoint": "downstream_consumer_or_export_sink",
              "reason": "required_by_STREAM_DISCONNECTED"
            }
          },
          "risk_level": "high",
          "requires_confirmation": true,
          "citations": [
            "diag-1",
            "flowdoc-stream-2",
            "snapshot-1"
          ]
        }
      ],
      "confidence": 0.94,
      "citations": [
        "diag-2",
        "diag-3",
        "diag-1",
        "flowdoc-stream-1",
        "flowdoc-unit-1",
        "flowdoc-stream-2",
        "snapshot-1"
      ]
    }
  ]
}
